using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_577b00c8ef0d4ef09c45dd4325227c19.Auth;

/// <summary>
/// Server-side provider that always returns a hardcoded authenticated user.
/// </summary>
public class HardcodedAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _authState = Task.FromResult(
        new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(
            new[]
            {
                new Claim(ClaimTypes.Name, "bob@example.com"),
                new Claim(ClaimTypes.Email, "bob@example.com"),
                new Claim(ClaimTypes.Role, "User"),
                new Claim(ClaimTypes.Role, "Editor"),
            },
            authenticationType: "Hardcoded"))));

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;

namespace sv_577b00c8ef0d4ef09c45dd4325227c19.Auth;

/// <summary>
/// Persists the current user's claims into PersistentComponentState so the
/// client-side WASM runtime can reconstruct the ClaimsPrincipal after handoff.
/// </summary>
public class PersistingAuthenticationStateProvider : AuthenticationStateProvider, IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private readonly PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authStateTask;

    public PersistingAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        _persistentState = persistentState;
        AuthenticationStateChanged += OnAuthenticationStateChanged;
        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
        => _authStateTask ?? Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
    {
        _authStateTask = authenticationStateTask;
        NotifyAuthenticationStateChanged(authenticationStateTask);
    }

    private void OnAuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        var authState = await GetAuthenticationStateAsync();
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var claims = principal.Claims.Select(c => new ClaimData { Type = c.Type, Value = c.Value }).ToArray();
            _persistentState.PersistAsJson("UserClaims", claims);
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
        AuthenticationStateChanged -= OnAuthenticationStateChanged;
    }
}

public class ClaimData
{
    public string Type { get; set; } = string.Empty;
    public string Value { get; set; } = string.Empty;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_577b00c8ef0d4ef09c45dd4325227c19.Client;

/// <summary>
/// Client-side (WASM) provider that reconstitutes the ClaimsPrincipal from
/// claims persisted by the server via PersistentComponentState.
/// </summary>
public class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<ClaimData[]>("UserClaims", out var claimData) && claimData is not null)
        {
            var claims = claimData.Select(c => new Claim(c.Type, c.Value));
            var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
            _authStateTask = Task.FromResult(new AuthenticationState(new ClaimsPrincipal(identity)));
        }
        else
        {
            _authStateTask = _unauthenticated;
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authStateTask;
}

public class ClaimData
{
    public string Type { get; set; } = string.Empty;
    public string Value { get; set; } = string.Empty;
}

@page "/profile"
@using Microsoft.AspNetCore.Components.Authorization
@using System.Security.Claims
@rendermode InteractiveAuto
@inject AuthenticationStateProvider AuthStateProvider

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>

        <h3>Roles</h3>
        <ul>
            @foreach (var role in context.User.Claims
                .Where(c => c.Type == ClaimTypes.Role)
                .Select(c => c.Value))
            {
                <li>@role</li>
            }
        </ul>
    </Authorized>
    <NotAuthorized>
        <p>You are not authenticated.</p>
    </NotAuthorized>
</AuthorizeView>

@page "/editor"
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize(Roles = "Editor")]
@rendermode InteractiveAuto

<PageTitle>Editor</PageTitle>

<h1>Editor</h1>

<p>Welcome to the Editor page. You have the <strong>Editor</strong> role.</p>

@page "/viewer"
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveAuto

<PageTitle>Viewer</PageTitle>

<h1>Viewer</h1>

<p>Welcome! This page is accessible to any authenticated user.</p>

